package cn.nobeta.dingdong.order.service;
import cn.nobeta.dingdong.order.domain.OrderOutbox;import cn.nobeta.dingdong.order.mapper.OrderOutboxMapper;import cn.nobeta.dingdong.order.mq.OrderTimeoutPublisher;import org.junit.jupiter.api.Test;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;
class OrderOutboxServiceTest {@Test void marksEventForRetryWhenPublishingFails(){OrderOutboxMapper mapper=mock(OrderOutboxMapper.class);OrderTimeoutPublisher publisher=mock(OrderTimeoutPublisher.class);OrderOutbox event=new OrderOutbox();event.setId(1L);event.setOrderNo("DD1");event.setStatus("PENDING");when(mapper.findById(1L)).thenReturn(event);doThrow(new IllegalStateException("broker down")).when(publisher).publish(any());new OrderOutboxService(mapper,publisher).publish(1L);verify(mapper).markRetry(eq(1L),contains("broker down"));verify(mapper,never()).markSent(anyLong());}}
